import{_ as e,c as a,o as l,a3 as r}from"./chunks/framework.CTM16EAR.js";const m=JSON.parse('{"title":"从这里开始","description":"","frontmatter":{},"headers":[],"relativePath":"guide/pomodoro-technique/00-start-here.md","filePath":"guide/pomodoro-technique/00-start-here.md","lastUpdated":1778035726000}'),i={name:"guide/pomodoro-technique/00-start-here.md"};function o(n,t,s,h,d,c){return l(),a("div",null,t[0]||(t[0]=[r('<h1 id="从这里开始" tabindex="-1">从这里开始 <a class="header-anchor" href="#从这里开始" aria-label="Permalink to &quot;从这里开始&quot;">​</a></h1><p>你的第一个番茄，从现在开始。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><ul><li>分区与控件名称以 <a href="./../reference/interface.html">软件界面</a> 为准；</li><li>尚未安装见 <a href="./../intro/install-overview.html">安装方式总览</a>。</li><li>想先随便转转、找条容易的上手方式，见 <a href="./../intro/easy-onboarding.html">轻松上手</a>。</li></ul></div><h2 id="什么是番茄工作法" tabindex="-1">什么是番茄工作法 <a class="header-anchor" href="#什么是番茄工作法" aria-label="Permalink to &quot;什么是番茄工作法&quot;">​</a></h2><ul><li>番茄工作法的核心很简单：</li></ul><ol><li><strong>选一个任务</strong></li><li><strong>设一个 25 分钟计时器</strong></li><li><strong>专注工作，直到计时器响</strong></li><li><strong>休息 5 分钟</strong></li><li><strong>重复</strong></li></ol><ul><li>这 25 分钟叫做<strong>一个番茄🍅</strong>，是这套方法的基本单位。</li><li>每 4 个番茄一组，休息 15-30 分钟。</li></ul><h2 id="你的第一个番茄" tabindex="-1">你的第一个番茄 <a class="header-anchor" href="#你的第一个番茄" aria-label="Permalink to &quot;你的第一个番茄&quot;">​</a></h2><ol><li>点击+加入一个任务，预估1个番茄，输入要做的事情</li><li>点击开始，记录当前时间；同时，番茄时钟启动计时。25 分钟只做与任务相关的事情。</li><li>计时结束，后打钩，数据统计从0变为1。</li></ol><p>恭喜🎉，你完成了第一个番茄。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>准备好深入了解？前往 <a href="./01-track-time.html">01-track-time.md</a>，学习如何通过记录弄清真实的时间消耗。</p>',12)]))}const p=e(i,[["render",o]]);export{m as __pageData,p as default};
